import soot.*;
import soot.options.Options;

public class Main {
	public static void main(String[] args) {
		/* Ensure dacapo-9.12-MR1-bach.jar and out-* directories (classes and refl.log generated by TamiFlex)
		are in the current directory */
		
		// Initialize Soot arguments
		GetSootArgs g = new GetSootArgs();
		String[] sootArgs = g.getDaCapoArgs(args[0]);

		if (sootArgs == null) {
			System.out.println("Unable to generate args for soot!");
			return;
		}
		
		// Inter-procedural static analysis
		MonomorphizationTransformer ipa = new MonomorphizationTransformer();
		PackManager.v().getPack("wjtp").add(new Transform("wjtp.ipa", ipa));

		Options.v().parse(sootArgs);
		Scene.v().loadNecessaryClasses();
		Scene.v().loadDynamicClasses();
		PackManager.v().runPacks();
	}
}